def solve(data):
    if not data:
        return None

    # Assuming data is a list of dictionaries with injury data
    processed_data = []
    for entry in data:
        if 'injury_type' in entry and 'count' in entry:
            processed_data.append({
                'type': entry['injury_type'],
                'count': entry['count']
            })

    return processed_data
